    let result = gallops.jjrg_rail(args);
    assert!(result.is_ok());

    let heat = gallops.heats.get(&heat_key).unwrap();
    assert_eq!(heat.order[0], pace2_key);
    assert_eq!(heat.order[1], original_first);
}

